const a={traditionalist:{code:"traditionalist",desc:{id:"Kamu memandang hunian sebagai jangkar sosial dan aksi kolektif. Gotong royong, memori kawasan, dan keadilan bermukim adalah nilai utamamu.",en:"You see housing as a social anchor and collective action. Mutual cooperation, neighborhood memory, and housing justice are your core values."},zona:"ZONA 1"},established:{code:"established",desc:{id:"Kamu realistis dan pragmatis soal hunian. Tapi prioritasmu juga ada pada stabilitas ekonomi, kelayakan fisik dasar, dan penyeimbangan akses.",en:"You are realistic and pragmatic about housing. Yet your priorities also lie in economic stability, basic physical feasibility, and balanced access."},zona:"ZONA 2"},urbanist:{code:"urbanist",desc:{id:"Mobilitas, efisiensi tinggi, dan konektivitas adalah segalanya bagimu. Kamu mengutamakan konektivitas tanpa batas melalui fasilitas publik.",en:"Mobility, high efficiency, and connectivity mean everything to you. You prioritize boundless connectivity through public facilities."},zona:"ZONA 3"},idealist:{code:"idealist",desc:{id:"Kamu mendambakan hunian mandiri energi yang menjadi infrastruktur ekologis pelindung diri sekaligus memulihkan lingkungan.",en:"You long for an energy‑independent housing that serves as ecological infrastructure; protecting yourself while also restoring the environment."},zona:"ZONA 4"}},n={defensive:{code:"defensive",desc:{id:"Punya dorongan kuat untuk melindungi diri, menuntut kedaulatan dan teritorial yang tinggi. Menolak berbagi struktur fisik dengan tetangga.",en:"Strong drive for self‑protection, demanding sovereignty and rigid territorial boundaries. Refuses to share physical structures with neighbors."},instruction:{id:"Balok diletakkan berdiri tegak, dilarang menumpang secara vertikal di atas struktur orang lain.",en:"Blocks must be placed standing upright; stacking vertically on another person’s structure is prohibited."}},consumptive:{code:"consumptive",desc:{id:"Didorong keinginan membangun citra. Ruang dipandang sebagai simbol status dan investasi. Setiap sudut harus terisi, tanpa ada yang kosong.",en:"Driven by the desire to build an image. Space is seen as a symbol of status and investment. Every corner must be filled, nothing left empty."},instruction:{id:"Balok wajib menjorok keluar batas grid yang diperbolehkan.",en:"Blocks must extend beyond the permitted grid boundary."}},paranoid:{code:"paranoid",desc:{id:"Membangun hunian sebagai perlindungan ekstrem, menutup akses publik demi rasa aman. Menghindari interaksi dengan lingkungan luar.",en:"Constructs housing as an extreme protection, shutting off public access for secure feeling. Avoiding interaction with the outside environment."},instruction:{id:"Balok dilarang menyentuh balok tetangga apapun caranya.",en:"Blocks must not touch neighboring blocks in any way."}},superficial:{code:"superficial",desc:{id:"Melakukan segala hal dengan kepraktisan instan, mengorbankan durabilitas jangka panjang demi keindahan visual dan gaya hidup sesaat.",en:"Acts with instant practicality, sacrificing long‑term durability for visual appeal and lifestyle aesthetics."},instruction:{id:"Balok diletakkan menempel atau miring pada struktur bangunan kokoh terdekat.",en:"Blocks must be placed leaning against or attached to the nearest solid building structure."}}},e={traditionalist:{defensive:{persona:"traditionalist",shadow:"defensive",warnaNama:"Dark Brown",warnaHex:"#88CBBC",model:{id:"Hunian Infill",en:"Urban Infill"},desc:{id:"Dibangun tanpa rencana, dan akhirnya menghancurkan perencanaan kota.",en:"Built without a plan, and in the end destroying city planning."}},consumptive:{persona:"traditionalist",shadow:"consumptive",warnaNama:"Nougat",warnaHex:"#DD17D50",model:{id:"Kampung Susun",en:"Vertical Cluster"},desc:{id:"Hunian yang hadir dari keterdesakan, sekaligus mudah disesaki keterbatasan.",en:"A housing built on urgency shaped by necessity, yet easily overwhelmed by its own constraints."}},paranoid:{persona:"traditionalist",shadow:"paranoid",warnaNama:"Dark Grey",warnaHex:"#800000",model:{id:"Klaster Tertutup",en:"Micro Cluster"},desc:{id:"Hunian dengan perlindungan tanpa celah, bahkan untuk keluarga terdekat.",en:"A housing with airtight protection, even against close family."}},superficial:{persona:"traditionalist",shadow:"superficial",warnaNama:"White",warnaHex:"#FFFFFF",model:{id:"Hunian-Rakit",en:"Stilt House"},desc:{id:"Simbol guyub sosial yang bisa tiba-tiba muncul, bisa tiba-tiba juga dirubuhkan.",en:"A symbol of social togetherness that can suddenly appear, and just as suddenly be torn down."}}},established:{defensive:{persona:"established",shadow:"defensive",warnaNama:"Light Grey",warnaHex:"#A7A7A7",model:{id:"Hunian Susun Tapak",en:"Vertical Townhouse"},desc:{id:"Maksudnya sih ingin terlindungi, tapi malah kadang mencemari.",en:"Well, the intention is to be protected, but sometimes it ends up polluting."}},consumptive:{persona:"established",shadow:"consumptive",warnaNama:"Black",warnaHex:"#000000",model:{id:"Kondominium",en:"Condominium"},desc:{id:"Dibangun setinggi mungkin, sampai menutupi cahaya sekitar.",en:"Built as high as possible, until it blocks the surrounding light."}},paranoid:{persona:"established",shadow:"paranoid",warnaNama:"Red",warnaHex:"#BA0C2F",model:{id:"Apartemen Satu Gerbang",en:"One-Gate Block"},desc:{id:"Mendukung ekosistem steril dari dunia luar yang tetap liar.",en:"Supporting a sterile ecosystem, cut off from the still-wild outside world."}},superficial:{persona:"established",shadow:"superficial",warnaNama:"Purple",warnaHex:"#FFCD00",model:{id:"Pod Huni Mandiri",en:"Self-Living Pod"},desc:{id:"Ruang huni individu untuk bisa sekadar tinggal di kota.",en:"An individual living space just to be able to stay in the city."}}},urbanist:{defensive:{persona:"urbanist",shadow:"defensive",warnaNama:"Yellow",warnaHex:"#6A2F8A",model:{id:"Hunian Transit",en:"Transit Loft"},desc:{id:"Mengisolasi diri di balik kaca kedap suara di antara lalu lalang.",en:"Isolating oneself behind soundproof glass amid the hustle and bustle."}},consumptive:{persona:"urbanist",shadow:"consumptive",warnaNama:"Orange",warnaHex:"#FF6D00",model:{id:"Studio Komuter",en:"Commuter Studio"},desc:{id:"Hunian bergengsi hasil 'negosiasi' penduduk asli.",en:"Prestigious housing born from “negotiations” with native residents."}},paranoid:{persona:"urbanist",shadow:"paranoid",warnaNama:"Blue",warnaHex:"#0051BA",model:{id:"Apartemen Skybridge",en:"Sky-Bridge Apartment"},desc:{id:"Punya jembatan langsung yang bikin semua di bawahnya diabaikan.",en:"Having a direct bridge that makes everything beneath it ignored."}},superficial:{persona:"urbanist",shadow:"superficial",warnaNama:"Pink",warnaHex:"#D20067",model:{id:"Hunian Kapsul Modular",en:"Plug-in Capsule"},desc:{id:"Ruang terbatas yang bikin permintaan ruang publik tidak terbatas.",en:"Limited space that creates unlimited demand for public space."}}},idealist:{defensive:{persona:"idealist",shadow:"defensive",warnaNama:"Light Blue",warnaHex:"#002A54",model:{id:"Pod Terapung",en:"Floating Pod"},desc:{id:"Hunian dengan sistem penyelamatan diri sendiri.",en:"A housing with a self-rescue system."}},consumptive:{persona:"idealist",shadow:"consumptive",warnaNama:"Lime Green",warnaHex:"#009639",model:{id:"Hunian Sirkular Mandiri",en:"Circular Housing"},desc:{id:"Hunian dengan teknologi hijau mandiri yang jadi simpanan sendiri.",en:"A housing with independent green technology kept as personal reserve."}},paranoid:{persona:"idealist",shadow:"paranoid",warnaNama:"Midnight Blue",warnaHex:"#002344",model:{id:"Hunian Berlapis",en:"Shell House"},desc:{id:"Dilengkapi filtrasi udara yang nggak sadar kemana terbuangnya.",en:"Equipped with air filtration, unaware of where the exhaust goes."}},superficial:{persona:"idealist",shadow:"superficial",warnaNama:"Green",warnaHex:"#009639",model:{id:"Kabin Hijau",en:"Eco Cabin"},desc:{id:"Hunian hijau yang menggarap area resapan.",en:"Green housing that works on water absorption areas."}}}};export{e as m,a as p,n as s};
